import api from '../../Api/api';
import { ApiStandardUser } from '../../Api/config';
import createNotification from 'src/components/Handle.Error/notifications';

const getAppointments = async () => {
    try {
        const result = await api.get(ApiStandardUser.api_Appointments);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};
const addAppointments = async (status) => {
    try {
        const result = await api.post(ApiStandardUser.api_Appointments, status);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};
const updateAppointments = async (id,data) => {
    try {
        const result = await api.put(ApiStandardUser.api_Appointments + id, data);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};
const getAppointmentsFilter = async (data) => {
    try {
        const result = await api.post(ApiStandardUser.api_Appointments + "filter", data);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));;
        return null;
    }
};


const AppointmentsFun = {
    getAppointments,
    addAppointments,
    updateAppointments,
    getAppointmentsFilter
};

export default AppointmentsFun;


